<?php // blog-post.php session_start(); require_once 'database.php'; require_once __DIR__. '/blog-setup.php'; $database = new Database(); $conn = $database->getConnection(); ensureBlogTables($conn); seedBlogData($conn); $slug = isset($_GET['slug'])? trim($_GET['slug']): ''; $post = null; if ($slug!== '') { $stmt = $conn->prepare("SELECT * FROM blog_posts WHERE slug =:slug AND status = 'published' LIMIT 1"); $stmt->execute([':slug' => $slug]); $post = $stmt->fetch(); } $recentStmt = $conn->prepare("SELECT id, title, slug, publish_date, featured_image FROM blog_posts WHERE status = 'published' ORDER BY publish_date DESC LIMIT 5"); $recentStmt->execute; $recentPosts = $recentStmt->fetchAll(); $canonicalUrl = $post? 'https://www.broadsafeservices.com.au/blog-post?slug='. rawurlencode((string)$post['slug']): 'https://www.broadsafeservices.com.au/blog-post'; $metaDescription = $post? htmlspecialchars((string)($post['meta_description']?: $post['excerpt'])): 'Security blog by Broadsafe Services'; $metaTitle = $post? htmlspecialchars((string)$post['title']). ' | Broadsafe Services': 'Blog Post | Broadsafe Services'; $metaImage = $post &&!empty($post['featured_image'])? htmlspecialchars((string)$post['featured_image']): 'https://www.broadsafeservices.com.au/images/og-image.png'; if (!preg_match('/^https?:\/\//', $metaImage)) { $metaImage = 'https://www.broadsafeservices.com.au/'. ltrim($metaImage, '/'); }?> <!DOCTYPE html>
